-- NollyCrew Production Houses & Companies
-- 605 companies
-- Run in Supabase SQL Editor

BEGIN;

CREATE TABLE IF NOT EXISTS companies (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name TEXT NOT NULL,
    wiki_url TEXT,
    website TEXT,
    location TEXT,
    industry TEXT DEFAULT 'film',
    description TEXT,
    founded_year INTEGER,
    founder TEXT,
    claim_status TEXT DEFAULT 'unclaimed',
    claimed_by UUID,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
  );

ALTER TABLE companies ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Public companies" ON companies FOR SELECT USING (true);
CREATE POLICY "Users can claim" ON companies FOR UPDATE USING (auth.uid() = claimed_by);


COMMIT;
-- Total: 605 companies